  symptom?: string;
  root_cause?: string;
  takeaway?: string;
  applies_when?: string;
  // Summary fields
  outcome?: 'success' | 'partial' | 'abandoned' | 'blocked';
  // Legacy learning/technique
  context?: string;
  applicability?: string;
  // Prompt quality fields (new taxonomy — v3.x)
